function firstName(name) {
  return String(name || 'cliente').trim().split(/\s+/)[0] || 'cliente';
}
const data = $json;
const ctx = data.context || {};
const nome = firstName(data.customer_name);
const scheduleLink = ctx.link_agendamento || ctx.link_reagendamento || null;
const meetingLink = ctx.link_videoconferencia || ctx.link_video || null;
let reply = '';
if (data.intent === 'cancelar_agendamento') {
  reply = 'Olá, ' + nome + '. Recebi sua solicitação de cancelamento do agendamento. Vou registrar isso e, se quiser um novo horário, posso te orientar por aqui.';
} else if (data.intent === 'reagendar_agendamento') {
  reply = scheduleLink
    ? 'Olá, ' + nome + '. Para reagendar seu atendimento, use este link: ' + scheduleLink
    : 'Olá, ' + nome + '. Recebi seu pedido de reagendamento. Vou deixar sua solicitação encaminhada para ajuste do horário.';
} else if (data.intent === 'link_videoconferencia') {
  reply = meetingLink
    ? 'Olá, ' + nome + '. Segue o link da sua videoconferência: ' + meetingLink
    : 'Olá, ' + nome + '. Ainda não encontrei o link da videoconferência neste contexto. Vou encaminhar para o time e te retorno.';
} else if (data.intent === 'enviar_documentos') {
  reply = 'Olá, ' + nome + '. Para agilizar a validação, envie por aqui os documentos solicitados antes do atendimento. Assim a equipe consegue seguir com mais rapidez.';
} else {
  reply = 'Olá, ' + nome + '. Estou acompanhando seu agendamento por aqui. Se precisar reagendar, mandar documentos ou pedir o link da videoconferência, pode me responder nesta conversa.';
}
return [{ json: { ...data, reply_text: reply, reply_subject: 'Continuidade do agendamento', event_type: 'commercial.validation_agenda.saved', entity_type: 'agendamentos_validacao' } }];
